88	struct RequestAbortGuard {
89	    bridge: Arc<PyBridge>,
90	    rid: String,
91	    armed: bool,
92	}
93	
94	impl RequestAbortGuard {
95	    fn new(bridge: Arc<PyBridge>, rid: impl Into<String>) -> Self {
96	        Self {
97	            bridge,
98	            rid: rid.into(),
99	            armed: true,
100	        }
101	    }
102	
103	    fn disarm(&mut self) {
104	        self.armed = false;
105	    }
106	
107	    fn abort_now(&mut self) {
108	        if self.armed {
109	            self.armed = false;
110	            spawn_abort(self.bridge.clone(), self.rid.clone());
111	        }
112	    }
113	}
114	
115	impl Drop for RequestAbortGuard {
116	    fn drop(&mut self) {
117	        if self.armed {
118	            // Dropping a response stream means the client stopped consuming; propagate
119	            // cancellation to Python without blocking the Tokio worker.
120	            spawn_abort(self.bridge.clone(), self.rid.clone());
121	        }
122	    }
123	}
124	
125	fn spawn_abort(bridge: Arc<PyBridge>, rid: String) {
126	    match tokio::runtime::Handle::try_current() {
127	        Ok(handle) => {
128	            let _ = handle.spawn_blocking(move || {
129	                let _ = bridge.abort(&rid, false);
130	            });
131	        }
132	        Err(_) => {
133	            tracing::warn!(
134	                rid,
135	                "Skipping gRPC request abort because no Tokio runtime is available"
136	            );
137	        }
138	    }
139	}
